window.onload = () => {
    
    var iconeDoTema = {
        'escuro' : 'noite',
        'claro' : 'dia'
    }
    
    let primeiroTema = localStorage.getItem('tema')
    document.body.setAttribute('tema', primeiroTema)
    const trocaTema = document.getElementById('troca-tema')
    if(trocaTema) {
        trocaTema.classList.add(iconeDoTema[primeiroTema])
        trocaTema.onclick = () => {
            var tema = localStorage.getItem('tema') == 'claro'? 'escuro' : 'claro'
            if (trocaTema.classList.length < 1)
                trocaTema.classList.add(iconeDoTema[tema])
            else
                trocaTema.classList.replace(trocaTema.classList[trocaTema.classList.length - 1], iconeDoTema[tema])
            document.body.setAttribute('tema', tema)
            localStorage.setItem('tema', tema)
        }
    }
}